SELECT id, employee_id, attendance_date, check_in_time, check_out_time, status, remark
FROM emp_attendance
WHERE employee_id = #{employeeId}

    AND attendance_date  >=  #{startDate}


    AND attendance_date  <=  #{endDate}

ORDER BY attendance_date ASC

SELECT id, employee_id, attendance_date, check_in_time, check_out_time, status, remark
FROM emp_attendance
WHERE employee_id = #{employeeId}
  AND status IN ('late', 'early_leave', 'absent', 'leave')

    AND attendance_date  >=  #{startDate}


    AND attendance_date  <=  #{endDate}

ORDER BY attendance_date ASC

SELECT COUNT(*) AS total_days, SUM(CASE WHEN status = 'normal' THEN 1 ELSE 0 END) AS normal_days, SUM(CASE WHEN status = 'late' THEN 1 ELSE 0 END) AS late_count, SUM(CASE WHEN status = 'early_leave' THEN 1 ELSE 0 END) AS early_leave_count, SUM(CASE WHEN status = 'absent' THEN 1 ELSE 0 END) AS absent_count, SUM(CASE WHEN status = 'leave' THEN 1 ELSE 0 END) AS leave_count, SUM(CASE WHEN status IN ('late', 'early_leave', 'absent', 'leave') THEN 1 ELSE 0 END) AS exception_total FROM emp_attendance WHERE employee_id = #{employeeId}
AND attendance_date >= #{startDate}
AND attendance_date <= #{endDate}

